sp_angular_provider.script:
function scmTableFiltersCoordinatorService(scmTableFilter) {
    "use strict";

    function populateConditionFromField(options) {
        options = options || {};

        return scmTableFilter.populateConditionFromField(
            options.condition,
            options.fieldConfig,
            {
                loadChoiceValues: options.loadChoiceValues,
            },
        );
    }

    function restoreFilterConditionsFromApplied(options) {
        options = options || {};

        return scmTableFilter.restoreFilterConditionsFromApplied({
            appliedFilters: options.appliedFilters,
            filterFieldMap: options.filterFieldMap,
            createEmptyFilterCondition:
                scmTableFilter.createEmptyFilterCondition,
            populateConditionFromField: function (condition, fieldConfig) {
                populateConditionFromField({
                    condition: condition,
                    fieldConfig: fieldConfig,
                    loadChoiceValues: options.loadChoiceValues,
                });
            },
        });
    }

    function initializeFilters(options) {
        options = options || {};

        var filterFieldMap = scmTableFilter.buildFilterFieldMap(
            options.filterFields || [],
        );
        var filters = restoreFilterConditionsFromApplied({
            appliedFilters: options.appliedFilters || [],
            filterFieldMap: filterFieldMap,
            loadChoiceValues: options.loadChoiceValues,
        });

        return {
            filterFieldMap: filterFieldMap,
            filters: filters,
        };
    }

    return {
        buildFilterFieldMap: scmTableFilter.buildFilterFieldMap,
        createEmptyFilterCondition: scmTableFilter.createEmptyFilterCondition,
        populateConditionFromField: populateConditionFromField,
        restoreFilterConditionsFromApplied: restoreFilterConditionsFromApplied,
        initializeFilters: initializeFilters,
        loadChoiceValues: scmTableFilter.loadChoiceValues,
        resolveReferenceFilterDisplayValues:
            scmTableFilter.resolveReferenceFilterDisplayValues,
    };
}
